import React, { useState } from 'react';
import {
  Container,
  Paper,
  Typography,
  Box,
  Button,
  Alert
} from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CloseIcon from '@mui/icons-material/Close';

const VerifyPage = () => {
  const [approved, setApproved] = useState(false);

  // This would come from your backend
  const testimonial = {
    original: "The coaching was good. I learned some things that helped me.",
    enhanced: "Working with this coach transformed how I approach challenges. I went from feeling stuck to landing two major clients in just 3 weeks. The coaching didn't just teach me tactics—it changed my entire mindset about what's possible."
  };

  return (
    <Container maxWidth="md" sx={{ py: 8 }}>
      <Paper sx={{ p: 4 }}>
        <Typography variant="h4" gutterBottom align="center">
          Verify Your Enhanced Testimonial
        </Typography>

        <Box sx={{ my: 4 }}>
          <Typography variant="subtitle1" gutterBottom>
            Original Testimonial:
          </Typography>
          <Typography variant="body1" sx={{ mb: 4, color: 'text.secondary' }}>
            "{testimonial.original}"
          </Typography>

          <Typography variant="subtitle1" gutterBottom>
            Enhanced Version:
          </Typography>
          <Typography variant="body1" sx={{ color: 'text.secondary' }}>
            "{testimonial.enhanced}"
          </Typography>
        </Box>

        {approved ? (
          <Alert 
            icon={<CheckCircleIcon fontSize="inherit" />} 
            severity="success"
            sx={{ mt: 4 }}
          >
            Thank you! The testimonial has been approved.
          </Alert>
        ) : (
          <Box sx={{ display: 'flex', gap: 2, justifyContent: 'center', mt: 4 }}>
            <Button
              variant="contained"
              color="primary"
              startIcon={<CheckCircleIcon />}
              onClick={() => setApproved(true)}
            >
              Approve Testimonial
            </Button>
            <Button
              variant="outlined"
              color="error"
              startIcon={<CloseIcon />}
            >
              Request Changes
            </Button>
          </Box>
        )}
      </Paper>
    </Container>
  );
};

export default VerifyPage;
